<?php declare(strict_types=1);

namespace SanderMuller\SolanaPhpSdk\Tests\Unit\Programs\SNS;

use PHPUnit\Framework\Attributes\Test;
use SanderMuller\SolanaPhpSdk\Programs\SNS\State\NameRegistryStateAccount;
use SanderMuller\SolanaPhpSdk\Tests\TestCase;
use SanderMuller\SolanaPhpSdk\Util\Buffer;

final class NameRegistryStateTest extends TestCase
{
    #[Test]
    public function deserialize(): void
    {
        $accountData = '';

        $decoded = base64_decode($accountData, true);
        self::assertNotFalse($decoded);

        $nameRegistryState = NameRegistryStateAccount::deserialize(
            Buffer::fromString($decoded)
        );

        self::assertSame('58PwtjSDuFHuUkYjH9BYnnQKHfwo9reZhC2zMJv9JPkx', $nameRegistryState->parentName->toBase58());
        self::assertSame('HKKp49qGWXd639QsuH7JiLijfVW5UtCVY4s1n2HANwEA', $nameRegistryState->owner->toBase58());
        self::assertSame('11111111111111111111111111111111', $nameRegistryState->class->toBase58());
    }

    #[Test]
    public function retrieve(): void
    {
        self::markTestSkipped('Requires live mainnet RPC to retrieve name registry state.');
    }
}
